double median(const std::vector<T>& data) {
    // Algorithm: For odd-sized vectors, returns the middle element.
    // For even-sized vectors, returns the average of the two middle elements.
    // Uses std::nth_element for O(n) average complexity instead of O(n log n) sorting.

