    std::vector<T> copy(data);
    size_t n = copy.size();
    size_t mid = n / 2;

    if (n % 2 == 1) {
        // Odd size: find the middle element
        std::nth_element(copy.begin(), copy.begin() + mid, copy.end());
        return static_cast<double>(copy[mid]);
    } else {
        // Even size: find both middle elements and average them
        std::nth_element(copy.begin(), copy.begin() + mid, copy.end());
        T upper = copy[mid];
        std::nth_element(copy.begin(), copy.begin() + mid - 1, copy.begin() + mid);
        T lower = copy[mid - 1];
        return (static_cast<double>(lower) + static_cast<double>(upper)) / 2.0;
